+    fn test_scope_new_captures_initial_state() {
+        let initial = N1Stats {
+            total_loads: 5,
+            relationships_loaded: 2,
+            potential_n1: 1,
+        };
+        let scope = N1DetectionScope::new(initial.clone(), 3);
